import { useTranslation } from 'react-i18next'
import BreadcrumbNav from '@common/Layout/components/BreadcrumbNav'
import PageWrapper from '@common/components/PageWrapper'
import {
  Anchor,
  Button,
  Collapse,
  Form,
  Grid,
  Input,
  Message,
  Select,
  Tooltip,
} from '@arco-design/web-react'
import {
  cloneElement,
  isValidElement,
  useCallback,
  useEffect,
  useRef,
  useState,
} from 'react'
import {
  IconClose,
  IconLoading,
  IconSave,
  IconUpload,
} from '@arco-design/web-react/icon'
import TimeSelectOne from './components/TimeSelectOne'
import {
  RiskCriticalityLevelColor,
  RiskTimeEnum,
  RiskImpactModeEnum,
} from '@/constants/risk'
import { ActionFlagEnum } from '@/constants/methodology'
import { initTimeData, handelClickData, getRiskImpactColor } from '@/utils/risk'
import LevelIcon from '@/assets/images/icon/level.svg?react'
import _ from 'lodash'
import { useRiskCriticalityLevelOptions } from '@/pages/Work/RiskCreationWizard/hooks/RiskCommon'
import { useRequest, useGetState } from 'ahooks'
import {
  getUserListAll,
  getRiskDetail,
  getSaveInherent,
  getControlList,
  riskMethodology,
  getRiskSaveResidual,
  getRiskSaveTreatment,
  getCategoryRiskList,
  getDepartmentTreeByUser as getOrgTreeRecursion,
} from '@/service'
import useDebouncedPromise from '@common/hooks/useDebouncedPromise'
import { useLocation, useNavigate, useParams } from 'react-router-dom'
import useUserInfo from '@common/hooks/useUserInfo'
import { useRiskCreationWizardOrgId } from '@common/hooks/useUserOrgInfo'
import { handelFieldNameShow, orgTransformData } from '@/utils/tools'
import './index.less'
import { useRiskStatusIconForForm } from '../../hooks/RiskCreationWizardCommon'
import { getLanguage } from '@common/utils/localStorage'
import { LanguageEnum } from '@common/constants/language'
import ImpactMatrix from './components/ImpactMatrix.tsx'
import LevelSelectInput from './components/LevelSelectInput'
import ProcessActivityPanel from './components/ProcessActivityPanel'
import ProceduresAndControl from './components/ProceduresAndControl'
import TreatmentApproachPanel from './components/TreatmentApproachPanel'
import {
  buildClassificationOptions,
  findClassificationByScore,
  getClassificationValue,
} from './utils/riskClassification'
import TreatmentPlanSection from './components/TreatmentPlanSection'
import { generateDefaultTreatmentTasks } from './utils/generateDefaultTreatmentTasks'
import { fixScoreRanges } from '@common/components/Shared/fixScoreRanges'
import { MaxLengthEnum } from '@common/constants/maxLength.ts'
const AnchorLink = Anchor.Link
const CollapseItem = Collapse.Item
const Row = Grid.Row
const Col = Grid.Col
const FormItem = Form.Item
const Option = Select.Option
const TextArea = Input.TextArea
const RiskDetail = () => {
  const classPrefix = 'risk'
  const { t } = useTranslation([
    'risk',
    'biaRecord',
    'common',
    'riskInformation',
    'methodology',
  ])
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const navigate = useNavigate()

  const [form2] = Form.useForm()
  const [followUpActionForm] = Form.useForm()
  const { riskId } = useParams()

  const location = useLocation()
  const riskNameLink = location?.state?.riskName || ''
  const activityName = location?.state?.activityName || ''
  const processName = location?.state?.process || ''
  const processNameAr = location?.state?.processAr || ''
  const methodologyId = location?.state?.methodologyId || ''

  const [impactAllData, setImpactAllData] = useState<any>()
  const [formOneData, setFormOneData] = useState({}) ///顶部详情

  const kpiTableRef = useRef(null)
  const [RiskImpact, setRiskImpact] = useState([...initTimeData])
  const [form1] = Form.useForm()
  const [RiskLikelihood, setRiskLikelihood] = useState([...initTimeData])
  const [impactList, setImpactList] = useState<any>()
  const [maxImpact, setMaxImpact] = useGetState(0)
  const [rateColor, setRateColor] = useState<any>(0)
  const [riskCategory, setRiskCategory] = useState(undefined) // 用于判断第一个模块 的输入框是哪个
  const riskImpactRef = useRef([])
  const riskLikelihoodRef = useRef([])

  const [riskImpactInput, setRiskImpactInput] = useState<any>()
  const [riskLikelihoodInput, setRiskLikelihoodInput] = useState<any>()
  const [residualMaxImpact, setResidualMaxImpact] = useState(0)
  const residualImpactRef3 = useRef([])
  const residualHood3 = useRef([])
  const [impactLevel, setImpactLevel] = useState<any>()
  const riskCriticalityLevelOptions = useRiskCriticalityLevelOptions()

  const [treatmentPlans, setTreatmentPlans] = useState<any>([])
  const treatmentAutoGeneratedFrequencyRef = useRef<string | null>(null)
  const [followUpActionVisible, setFollowUPActionVisible] = useState<any>(false)
  const [breadCrumbObj, setBreadCrumbObj] = useState({
    riskNameLink: '',
  })

  const riskStatusIconObj = useRiskStatusIconForForm()

  const [impactMode, setImpactMode] = useState<any>()
  const [currentOverallEffectiveness, setCurrentOverallEffectiveness] =
    useState<string | number | undefined>()
  const [currentTreatmentApproach, setCurrentTreatmentApproach] = useState<
    string | number | undefined
  >()
  const [processActivityValidateState, setProcessActivityValidateState] =
    useState({
      isRelatedProcessComplete: true,
    })
  const [, setIsTreatment] = useState(false)
  const [, setIsTreatmentByRateTolerance] = useState(false)

  const updateTreatmentByRateTolerance = (rate: any) => {
    const tolerance = Number(impactAllData?.rateTolerance)
    const rateValue = Number(rate)

    if (_.isNil(impactAllData?.rateTolerance) || _.isNil(rate) || rate === '') {
      setIsTreatmentByRateTolerance(false)
      return
    }

    if (Number.isNaN(tolerance) || Number.isNaN(rateValue)) {
      setIsTreatmentByRateTolerance(false)
      return
    }

    setIsTreatmentByRateTolerance(rateValue >= tolerance)
  }

  const navigateBackToDetail = () => {
    if (window.history.length > 1) {
      navigate(-1)
      return
    }
    navigate(`/work/risk-creation-wizard/create`)
  }

  useEffect(() => {
    setBreadCrumbObj({
      riskNameLink, // 获取名字
    })
  }, [riskNameLink])

  const breadcrumbList = [
    {
      path: '/work/risk-creation-wizard/create',
      breadcrumbName: t('risk:riskRegister'),
    },
    {
      path: `/work/risk-creation-wizard/detail`,
      breadcrumbName: breadCrumbObj?.riskNameLink,
    },
  ]

  const anchorRef = useRef<any>(null)
  const AnchorLinkTitle = (title: string, status?: number | null) => {
    const statusValue = status === 1 ? 1 : 0
    const statusIcon = riskStatusIconObj[statusValue]
    const iconNode = isValidElement(statusIcon)
      ? cloneElement(statusIcon)
      : statusIcon

    return (
      <div className={`anchor-link-title`}>
        <span className={`anchor-link-title-icon`}>{iconNode}</span>
        <Tooltip content={title} position={isLanguageAR ? 'left' : 'right'}>
          <span className={`anchor-link-title-text`}>{title}</span>
        </Tooltip>
      </div>
    )
  }

  const [riskDetailData, setRiskDetailData] = useState<any>()
  const updateRiskDetailStatus = (field: string) => {
    setRiskDetailData((prev) => ({
      ...(prev || {}),
      [field]: 1,
    }))
  }

  const [classificationOptions, setClassificationOptions] = useState<any[]>([])
  const [inherentRateTextColor, setInherentRateTextColor] = useState('')
  const [residualRateTextColor, setResidualRateTextColor] = useState('')

  const getClassificationByRate = (score: number) => {
    return findClassificationByScore(
      Number(score),
      fixScoreRanges(impactAllData?.classificationItemBOList || []),
    )
  }

  const getClassificationResultByRate = (score: number) => {
    const fallbackLevel = getRiskImpactColor(score) || 0
    const target = getClassificationByRate(score)
    const value = getClassificationValue(target) ?? fallbackLevel
    const color = target?.color || RiskCriticalityLevelColor[value] || ''
    return {
      value,
      color,
    }
  }

  const { run: getRiskMethodology, loading: riskMethodologyLoading } =
    useRequest(riskMethodology, {
      manual: true,
      onSuccess: (res: any) => {
        setImpactAllData(res)
        setImpactMode(res?.impactMode)

        const list = buildClassificationOptions(
          fixScoreRanges(res?.classificationItemBOList || []),
          isLanguageAR,
        )
        setClassificationOptions(list)

        const likelihoodConfigList = res?.likelihoodItemBOList || []
        if (likelihoodConfigList.length) {
          const likelihoodLevels = [...likelihoodConfigList]
            .sort((a, b) => a.level - b.level)
            .map((item) => ({
              key: String(item.level),
              value:
                String(item.level) ===
                String(riskDetailData?.inherentLikelihood)
                  ? 'selected'
                  : '',
              color: item.color,
            }))
          setRiskLikelihood(likelihoodLevels)
          riskLikelihoodRef.current = likelihoodLevels
        }

        if (riskDetailData) {
          const inherentResult = getClassificationResultByRate(
            Number(riskDetailData?.inherentRate),
          )
          const residualResult = getClassificationResultByRate(
            Number(riskDetailData?.residualRate),
          )

          setRateColor(inherentResult.value)
          setInherentRateTextColor(inherentResult.color)
          setResidualRateTextColor(residualResult.color)

          form1.setFieldValue(
            'inherentRiskClassification',
            inherentResult.value,
          )
          form2.setFieldValue(
            'residualRiskClassification',
            residualResult.value,
          )
          updateTreatmentByRateTolerance(Number(riskDetailData?.residualRate))
        }
      },
    })

  useEffect(() => {
    setClassificationOptions(
      buildClassificationOptions(
        fixScoreRanges(impactAllData?.classificationItemBOList || []),
        isLanguageAR,
      ),
    )
  }, [impactAllData, isLanguageAR])

  const impactListFunction = useCallback(
    (riskData, type) => {
      const methodologyList =
        impactAllData?.domainAppetiteDetailItemBOList || []

      if (!methodologyList.length) return []

      // 如果 riskData 有数据 → 合并
      if (riskData && riskData.length > 0) {
        const result = methodologyList.map((methodItem, index) => {
          const match = riskData.find(
            (riskItem) => riskItem.domainId === methodItem.domainId,
          )

          return {
            ...methodItem,
            ...match, // 覆盖 level / reason
            id: index,
            domainId: methodItem?.domainId,
            name: methodItem?.domainName,
            nameAr: methodItem?.domainNameAr,
            levels: methodItem?.domainImpactLevelDetailItemBOList?.map(
              (level) => {
                return {
                  ...level,
                }
              },
            ),
            appetiteLevel: methodItem?.appetiteLevel,
            toleranceLevel: methodItem?.toleranceLevel,
            escalateLine: methodItem?.escalateLine,
            breachLine: methodItem?.breachLine,
            level: match?.level ?? null,
            reasons: match?.reasons ?? '',
          }
        })
        setImpactList(result)
        return
      }
      // 如果 riskData 没数据 → 直接用 methodology
      const result = methodologyList.map((item, index) => ({
        id: index,
        domainId: item?.domainId,
        name: item?.domainName,
        nameAr: item?.domainNameAr,
        level: null,
        reasons: '',
        levels: item?.domainImpactLevelDetailItemBOList?.map((level) => {
          return {
            ...level,
          }
        }),
        appetiteLevel: item?.appetiteLevel,
        toleranceLevel: item?.toleranceLevel,
        escalateLine: item?.escalateLine,
        breachLine: item?.breachLine,
      }))
      setImpactList(result)
      return
    },
    [impactAllData?.domainAppetiteDetailItemBOList],
  )

  useEffect(() => {
    if (impactAllData?.domainAppetiteDetailItemBOList && riskDetailData) {
      impactListFunction(riskDetailData?.inherentImpacts, false)
      impactListFunction(riskDetailData?.residualImpacts, true)
    }
  }, [impactAllData, riskDetailData, impactListFunction])

  const { loading: riskDetailLoading, runAsync: runRiskDetail } = useRequest(
    // activityRiskDetail,
    getRiskDetail,
    {
      manual: true,
      onSuccess: (res: any) => {
        setRiskDetailData(res)
        const riskDetailData = res
        const currentRiskCategoryId = riskDetailData?.riskCategoryId
        setFormOneData({
          riskName: handelFieldNameShow(
            riskDetailData?.name,
            riskDetailData?.nameAr,
          ),
          riskCategory: riskDetailData?.riskCategoryId,
          riskDescription: handelFieldNameShow(
            riskDetailData?.description,
            riskDetailData?.descriptionAr,
          ),
        })
        setMaxImpact(riskDetailData?.inherentMaxImpact)
        setResidualMaxImpact(riskDetailData?.residualMaxImpact)
        setControlsList(
          riskDetailData?.controls ? riskDetailData?.controls : [],
        )
        setCurrentTreatmentApproach(riskDetailData?.treatmentApproach)
        setCurrentOverallEffectiveness(
          riskDetailData?.overallControlEffectiveness,
        )
        setTreatmentPlans(riskDetailData?.treatmentPlans || [])
        setImpactLevel(riskDetailData?.residualMaxImpact)
        getRiskMethodology({
          methodologyId: methodologyId,
          categoryId: riskDetailData?.riskCategoryId,
        })
        const residualImpacts = Array.isArray(riskDetailData?.residualImpacts)
          ? riskDetailData.residualImpacts
          : []
        const lastItem = residualImpacts[residualImpacts.length - 1]
        setRiskLikelihoodInput(riskDetailData?.inherentLikelihoodNote)
        residualImpactRef3.current = [riskDetailData?.residualMaxImpact]
        residualHood3.current = [riskDetailData?.residualLikelihood]
        riskImpactRef.current = [riskDetailData?.inherentMaxImpact]
        const formData1 = {
          name: riskDetailData?.name,
          nameAr: riskDetailData?.nameAr,
          riskCategory: riskDetailData?.riskCategory ?? undefined,
          riskDescription: riskDetailData?.riskDescription,
          riskDescriptionAr: riskDetailData?.riskDescriptionAr,
          impact: riskDetailData?.inherentMaxImpact,
          likelihood: riskDetailData?.inherentLikelihood,
          rate: riskDetailData?.inherentRate,
          inherentRiskClassification:
            riskDetailData?.inherentRiskClassification || undefined,
        }
        const formData2 = {
          name: riskDetailData?.name,
          nameAr: riskDetailData?.nameAr,
          riskCategory: riskDetailData?.riskCategory ?? undefined,
          residualImpact: riskDetailData?.residualMaxImpact,
          residualImpactLikelihood: riskDetailData?.residualLikelihood,
          residualImpactRate: riskDetailData?.residualRate,
          residualRiskClassification:
            riskDetailData?.residualInherentRiskClassification || undefined,
          residualAssessmentComment:
            riskDetailData?.residualAssessmentComment || '',
        }

        //////////////////第一个
        setRiskCategory(currentRiskCategoryId)
        const inherentResult = getClassificationResultByRate(
          Number(riskDetailData?.inherentRate),
        )

        const initImpactNew = initTimeData.map((item) => ({
          ...item,
          value:
            item.key === String(riskDetailData?.inherentMaxImpact)
              ? 'selected'
              : item.value,
        }))
        setRiskImpact(initImpactNew)

        const likelihoodNew = initTimeData.map((item) => ({
          ...item,
          value:
            item.key === String(riskDetailData?.inherentLikelihood)
              ? 'selected'
              : item.value,
        }))
        riskLikelihoodRef.current = likelihoodNew
        setRiskLikelihood(likelihoodNew)
        setRateColor(inherentResult.value)
        setInherentRateTextColor(inherentResult.color)
        form1.setFieldsValue(formData1)
        form1.setFieldsValue({
          relatedProcess: riskDetailData?.relatedProcess || [],
          inherentRiskClassification: inherentResult.value,
        })

        ////第二个
        const residualResult = getClassificationResultByRate(
          Number(riskDetailData?.residualRate),
        )
        setResidualRateTextColor(residualResult.color)
        form2.setFieldsValue(formData2)
        form2.setFieldValue('residualRiskClassification', residualResult.value)
      },
    },
  )

  //第一个select 的 数据
  const [processOptions, setProcessOptions] = useState<any[]>([])
  const { run: CategoryRiskList } = useRequest(getCategoryRiskList, {
    manual: true,
    onSuccess(data: any) {
      const processOptionsData = data.map((item) => {
        return {
          label: handelFieldNameShow(item.name, item.nameAr),
          value: item.configId,
          typeCode: item.typeCode,
          domainIds: item.domainIds,
        }
      })
      setProcessOptions(processOptionsData || [])
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })

  const getLinkedDomains = () => {
    const domains = impactAllData?.domainAppetiteDetailItemBOList || []

    if (!Array.isArray(domains) || domains.length === 0) return ''

    return (
      <div className='risk-domains-grid'>
        {domains.map((d, idx) => (
          <span key={idx} className='risk-domains-item'>
            {isLanguageAR ? d.domainNameAr : d.domainName}
          </span>
        ))}
      </div>
    )
  }

  const userInfo = useUserInfo()
  const { userId } = userInfo
  const orgId = useRiskCreationWizardOrgId()

  //初始加载数据
  useEffect(() => {
    CategoryRiskList({
      keyword: '',
      userId,
      orgId,
    })
    getUserList({})
    runRiskDetail({ riskId })
  }, [riskId, CategoryRiskList, runRiskDetail, userId, orgId])

  const [orgData, setOrgData] = useState<any>()
  useEffect(() => {
    getOrgTreeRecursion().then((res: any) => {
      setOrgData(orgTransformData(res))
    })
  }, [])

  //自动计算的 辅助函数
  const handelSelectData = (data: number, type: string) => {
    switch (type) {
      case RiskTimeEnum.RiskImpact:
        form1.setFieldsValue({
          impact: data,
        })
        break

      case RiskTimeEnum.RiskLikelihood:
        form1.setFieldsValue({
          likelihood: data,
        })
        break
    }
  }

  const handelClickLevel3 = (level: string, type: string, index: string) => {
    if (type === RiskTimeEnum.ResidualImpactList) {
      residualImpactRef3.current = [index]
      form2.setFieldsValue({
        residualImpact: index,
      })
    }

    if (type === RiskTimeEnum.ResidualLikelihood) {
      residualHood3.current = [index]
      form2.setFieldsValue({
        residualImpactLikelihood: index,
      })
    }

    getResidualRate3(type)
  }
  const hasSelectValue3 = (data: any) => {
    return data[0] !== ''
  }
  const getResidualRate3 = (type) => {
    if (type == RiskTimeEnum.ResidualImpactList) {
      if (hasSelectValue3(residualImpactRef3.current)) {
        const riskImpactSelectValue = residualImpactRef3.current[0]
        const riskLikelihoodSelectValue = residualHood3.current[0]
        const riskRateValue =
          +riskImpactSelectValue * +riskLikelihoodSelectValue
        const residualResult = getClassificationResultByRate(riskRateValue)
        setResidualRateTextColor(residualResult.color)

        form2.setFieldValue('residualImpactRate', riskRateValue)
        form2.setFieldValue('residualRiskClassification', residualResult.value)
        updateTreatmentByRateTolerance(riskRateValue)
      } else {
        setResidualRateTextColor('')
        form2.setFieldValue('residualImpactRate', '')
        form2.setFieldValue('residualRiskClassification', undefined)
        updateTreatmentByRateTolerance('')
      }
    } else {
      if (hasSelectValue3(residualHood3.current)) {
        const riskImpactSelectValue = residualImpactRef3.current[0]
        const riskLikelihoodSelectValue = residualHood3.current[0]
        const riskRateValue =
          +riskImpactSelectValue * +riskLikelihoodSelectValue
        const residualResult = getClassificationResultByRate(riskRateValue)
        setResidualRateTextColor(residualResult.color)

        form2.setFieldValue('residualImpactRate', riskRateValue)
        form2.setFieldValue('residualRiskClassification', residualResult.value)
        updateTreatmentByRateTolerance(riskRateValue)
        // get residual risk strategy value
      } else {
        setResidualRateTextColor('')
        form2.setFieldValue('residualImpactRate', '')
        form2.setFieldValue('residualRiskClassification', undefined)
