      handelSelectData(+selectData, type)
      setRiskImpact(processData)
    }
    if (type === RiskTimeEnum.RiskImpactList) {
      riskImpactRef.current = [index]
    }
    if (type === RiskTimeEnum.RiskLikelihood) {
      const processData = handelClickData(level, RiskLikelihood, index)
      riskLikelihoodRef.current = processData
      const selectData = processData.filter(
        (item) => item.value === 'selected',
