        const riskLikelihoodSelectValue = riskLikelihoodRef.current.filter(
          (item) => item.value !== '',
        )[0]['key']
        const riskRateValue =
          +riskImpactSelectValue * +riskLikelihoodSelectValue
        const inherentResult = getClassificationResultByRate(riskRateValue)
        setRateColor(inherentResult.value)
        setInherentRateTextColor(inherentResult.color)
        form1.setFieldValue('rate', riskRateValue)
        form1.setFieldValue('inherentRiskClassification', inherentResult.value)
