import { useEffect, useRef, useState } from 'react'
import { Button, Collapse, Radio, Message } from '@arco-design/web-react'
import { IconSave } from '@arco-design/web-react/icon'
import { useTranslation } from 'react-i18next'
import { useRequest } from 'ahooks'
import { getRiskSaveTreatmentApproach } from '@/service'
import {
  TreatmentApproachOptions,
  TreatmentApproachEnum,
} from '../ProceduresAndControl/constants'
import './index.less'

const CollapseItem = Collapse.Item

interface TreatmentApproachPanelProps {
  riskId?: string
  detailData?: any
  saveTrigger?: number
  saveLoading?: boolean
  onSave?: (treatmentApproach: number | undefined) => void
  onSaveSuccess?: () => void
  onTreatmentApproachChange?: (val: number | undefined) => void
}

const TreatmentApproachPanel: React.FC<TreatmentApproachPanelProps> = ({
  riskId,
  detailData,
  saveTrigger,
  saveLoading = false,
  onSave,
  onSaveSuccess,
  onTreatmentApproachChange,
}) => {
  const { t } = useTranslation(['risk', 'common', 'riskCreationWizard'])

  const [treatmentApproach, setTreatmentApproach] = useState<number | undefined>(
    detailData?.treatmentApproach,
  )
  const isFirstSaveTrigger = useRef(true)

  useEffect(() => {
    setTreatmentApproach(detailData?.treatmentApproach)
    onTreatmentApproachChange?.(detailData?.treatmentApproach)
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [detailData?.treatmentApproach])

  const { run: saveTreatmentApproach, loading: saveApproachLoading } =
    useRequest(getRiskSaveTreatmentApproach, {
      manual: true,
      onSuccess: () => {
        onSaveSuccess?.()
        Message.success(t('common:message.saveSuccessfully'))
      },
    })

  const handleSave = () => {
    if (!riskId) {
      Message.warning(t('common:pleaseSelect'))
      return
    }
    if (!treatmentApproach) {
      Message.error(
        t('riskCreationWizard:riskDetail.pleaseSelectTreatmentApproach'),
      )
      return
    }
    saveTreatmentApproach({ riskId, treatmentApproach })
    onSave?.(treatmentApproach)
  }

  useEffect(() => {
    if (saveTrigger === undefined) return
    if (isFirstSaveTrigger.current) {
      isFirstSaveTrigger.current = false
      return
    }
    handleSave()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [saveTrigger])

  return (
    <div className='treatment-approach-panel'>
      <Collapse
        className='common-collapse'
        expandIconPosition='right'
        defaultActiveKey={['treatmentApproach']}
      >
        <CollapseItem
          header={t('riskCreationWizard:riskDetail.treatmentApproach')}
          name='treatmentApproach'
        >
          <div className='ta-section'>
            <Radio.Group
              value={treatmentApproach}
              onChange={(val) => {
                setTreatmentApproach(val)
                onTreatmentApproachChange?.(val)
              }}
              className='ta-radio-group'
            >
              {TreatmentApproachOptions.map((opt) => (
                <Radio key={opt.value} value={opt.value}>
                  {t(
                    `risk:form2.riskManagementStrategyOptions.${TreatmentApproachEnum[opt.value].toLowerCase()}`,
                  )}
                </Radio>
              ))}
            </Radio.Group>
          </div>

          <div className='risk-save-btn'>
            <Button
              type='primary'
              icon={<IconSave />}
              className='save-btn'
              loading={saveLoading || saveApproachLoading}
              onClick={handleSave}
            >
              {t('common:btn.save')}
            </Button>
          </div>
        </CollapseItem>
      </Collapse>
    </div>
  )
}

