import { useEffect, useRef, useState } from 'react'
import { Button, Collapse, Radio, Message, Form, Input } from '@arco-design/web-react'
import { IconSave } from '@arco-design/web-react/icon'
import { useTranslation } from 'react-i18next'
import { useRequest } from 'ahooks'
import { getRiskSaveTreatmentApproach } from '@/service'
import {
  TreatmentApproachOptions,
  TreatmentApproachEnum,
} from '../ProceduresAndControl/constants'
import './index.less'

const CollapseItem = Collapse.Item
const FormItem = Form.Item
const TextArea = Input.TextArea

interface TreatmentApproachPanelProps {
  riskId?: string
  detailData?: any
  saveTrigger?: number
  saveLoading?: boolean
  onSave?: (treatmentApproach: number | undefined) => void
  onSaveSuccess?: () => void
  onTreatmentApproachChange?: (val: number | undefined) => void
}

const TreatmentApproachPanel: React.FC<TreatmentApproachPanelProps> = ({
  riskId,
  detailData,
  saveTrigger,
  saveLoading = false,
  onSave,
  onSaveSuccess,
  onTreatmentApproachChange,
}) => {
  const { t } = useTranslation(['risk', 'common', 'riskCreationWizard'])
  const [form] = Form.useForm()

  const [treatmentApproach, setTreatmentApproach] = useState<number | undefined>(
    detailData?.treatmentApproach,
  )
  const isFirstSaveTrigger = useRef(true)

  useEffect(() => {
    const approach = detailData?.treatmentApproach
    setTreatmentApproach(approach)
    onTreatmentApproachChange?.(approach)
    if (approach) {
      form.setFieldsValue({
        justification: detailData?.justification ?? '',
        justificationAr: detailData?.justificationAr ?? '',
        transferTarget: detailData?.transferTarget ?? '',
        transferTargetAr: detailData?.transferTargetAr ?? '',
        transferTerms: detailData?.transferTerms ?? '',
        transferTermsAr: detailData?.transferTermsAr ?? '',
      })
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [detailData?.treatmentApproach])

  const { run: saveTreatmentApproach, loading: saveApproachLoading } =
    useRequest(getRiskSaveTreatmentApproach, {
      manual: true,
      onSuccess: () => {
        onSaveSuccess?.()
        Message.success(t('common:message.saveSuccessfully'))
      },
    })

  const handleSave = () => {
    if (!riskId) {
      Message.warning(t('common:pleaseSelect'))
      return
    }
    if (!treatmentApproach) {
      Message.error(
        t('riskCreationWizard:riskDetail.pleaseSelectTreatmentApproach'),
      )
      return
    }
    form.validate().then((values) => {
      saveTreatmentApproach({
        riskId,
        treatmentApproach,
        justification: values.justification || undefined,
        justificationAr: values.justificationAr || undefined,
        transferTarget: values.transferTarget || undefined,
        transferTargetAr: values.transferTargetAr || undefined,
        transferTerms: values.transferTerms || undefined,
        transferTermsAr: values.transferTermsAr || undefined,
      })
      onSave?.(treatmentApproach)
    })
  }

  useEffect(() => {
    if (saveTrigger === undefined) return
    if (isFirstSaveTrigger.current) {
      isFirstSaveTrigger.current = false
      return
    }
    handleSave()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [saveTrigger])

  const renderConditionalFields = () => {
    if (!treatmentApproach) return null
    return (
      <Form form={form} layout='vertical' style={{ marginTop: 16 }}>
        <FormItem
          field='justification'
          label={t('risk:treatment.justification')}
          rules={[{ required: true, message: t('risk:treatment.justificationRequired') }]}
        >
          <TextArea rows={3} maxLength={2000} showWordLimit placeholder={t('common:pleaseEnter')} />
        </FormItem>
        <FormItem
          field='justificationAr'
          label={t('risk:treatment.justificationAr')}
        >
          <TextArea rows={3} maxLength={2000} showWordLimit dir='rtl' placeholder={t('common:pleaseEnter')} />
        </FormItem>

        {treatmentApproach === TreatmentApproachEnum.Transfer && (
          <>
            <FormItem
              field='transferTarget'
              label={t('risk:treatment.transferTarget')}
            >
              <Input maxLength={500} placeholder={t('common:pleaseEnter')} />
            </FormItem>
            <FormItem
              field='transferTargetAr'
              label={t('risk:treatment.transferTargetAr')}
            >
              <Input maxLength={500} dir='rtl' placeholder={t('common:pleaseEnter')} />
            </FormItem>
            <FormItem
              field='transferTerms'
              label={t('risk:treatment.transferTerms')}
            >
              <TextArea rows={3} maxLength={2000} showWordLimit placeholder={t('common:pleaseEnter')} />
            </FormItem>
            <FormItem
              field='transferTermsAr'
              label={t('risk:treatment.transferTermsAr')}
            >
              <TextArea rows={3} maxLength={2000} showWordLimit dir='rtl' placeholder={t('common:pleaseEnter')} />
            </FormItem>
          </>
        )}
      </Form>
    )
  }

  return (
    <div className='treatment-approach-panel'>
      <Collapse
        className='common-collapse'
        expandIconPosition='right'
        defaultActiveKey={['treatmentApproach']}
      >
        <CollapseItem
          header={t('riskCreationWizard:riskDetail.treatmentApproach')}
          name='treatmentApproach'
        >
          <div className='ta-section'>
            <Radio.Group
              value={treatmentApproach}
              onChange={(val) => {
                setTreatmentApproach(val)
                onTreatmentApproachChange?.(val)
                form.resetFields()
              }}
              className='ta-radio-group'
            >
              {TreatmentApproachOptions.map((opt) => (
                <Radio key={opt.value} value={opt.value}>
                  {t(
                    `risk:form2.riskManagementStrategyOptions.${TreatmentApproachEnum[opt.value].toLowerCase()}`,
                  )}
                </Radio>
              ))}
            </Radio.Group>
          </div>

          {renderConditionalFields()}

          <div className='risk-save-btn'>
            <Button
              type='primary'
              icon={<IconSave />}
              className='save-btn'
              loading={saveLoading || saveApproachLoading}
              onClick={handleSave}
            >
              {t('common:btn.save')}
            </Button>
          </div>
        </CollapseItem>
      </Collapse>
